```html
%@LW_pgstart@@
<html>
  <head>
    <title>%@LW_PField_s_prnFile@%</title>
    <style>
      body {
        background-color: #fff;
      }

      th {
        height: 10px;
        font-weight: bold;
      }

      .isi tr:nth-child(even) td {
        background-color: #ededed;
      }

      .customers tr:hover {
        background-color: #ddd;
      }

      table {
        border-collapse: collapse;
      }

      .isi table,
      .isi td,
      .isi th {
        /* border: 1px solid black; */
        font-size: 13px
      }

      #head table,
      #head td,
      #head th {
        border: none !important;
      }

      @media print and (min-resolution: 144dpi) {

        .no-print,
        .no-print * {
          display: none !important;
        }
      }
    </style>
    <style>
      table {
        font-size: 12px;
      }

      .p {
        padding: 5px;
      }

      .bt {
        border-top: 1px solid;
      }

      .br {
        border-right: 1px solid;
      }

      .bb {
        border-bottom: 1px solid;
      }

      .bl {
        border-left: 1px solid;
      }

      .ba {
        border: 1px solid;
      }
    </style>
  </head>
  <body bgcolor="#ffffff" text="#000" style="font-family:arial;">

    LW_pgstart@%

    %@LW_prowno_0@@
    <button class="no-print" onclick="window.print()">Print</button>
    <table class="isi">
    <thead>
      <tr>
        <th rowspan="2" class="p ba">Invoice</th>
        <th class="p ba">Cust. Code</th>
        <th rowspan="2" class="p ba">Description</th>
        <th rowspan="2" class="p ba">Status</th>
        <th class="p ba">Inv. Date</th>
        <th class="p ba">Due Date</th>
        <th rowspan="2" class="p ba" width="80px">Amount</th>
        <th rowspan="2" class="p ba" width="80px">Discount</th>
        <th rowspan="2" class="p ba" width="80px">Tax</th>
        <th rowspan="2" class="p ba" width="80px">Inv. Amount</th>
      </tr>
      <tr>
        <th class="p ba">Stock Code</th>
        <th class="p ba">QTY Req.</th>
        <th class="p ba">QTY Inv.</th>
      </tr>
    </thead>
      LW_prowno_0@%


     %@LW_prowno_10@@
    <tbody>
      <tr>
        <td class="p ba">%@LW_PField_fa_Nofak@%</td>
        <td class="p ba">%@LW_PField_fa_Nocust@%</td>
        <td class="p ba">%@LW_PField_fa_Name@%</td>
        <td class="p ba">%@LW_PField_fa_statux+fa_printx +fa_status+fa_print@%</td>
        <td class="p ba" style="padding-left:5px">%@LW_PField_DtoStr(fa_Dtfak,DD/MM/YY)@%</td>
        <td class="p ba" style="padding-left:5px">%@LW_PField_DtoStr(fa_Dtdue,DD/MM/YY)@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_hrg@N16/0,N,13,1@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_hpot@N16/0,N,14,1@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_htax@N16/0,N,16,1@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_harga-fa_htax@N16/0,N,17,1@%</td>
      </tr>
      LW_prowno_10@% 

      %@LW_prowno_11@@
      <tr>
        <td class="p ba"></td>
        <td class="p ba">%@LW_PField_fa_itemID@%</td>
        <td class="p ba">%@LW_PField_fa_descr@%</td>
        <td class="p ba"></td>
        <td class="p ba" style="padding-left:5px">%@LW_PField_fa_qtx@%</td>
        <td class="p ba" style="padding-left:5px">%@LW_PField_fa_qty@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_hrg@N16/0,N,13,1@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_hpot@N16/0,N,14,1@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_htax@N16/0,N,16,1@%</td>
        <td class="p ba" width="80px" align="right">%@LW_PField_fa_hrg-fa_hpot-fa_htax@N16/0,N,17,1@%</td>
      </tr>
      LW_prowno_11@%

      %@LW_prowno_111@@
      LW_prowno_111@%

    %@LW_pgend@@
    </table>
  </body>
</html>
LW_pgend@%
